trigger.body:
  v_reason_clousure VARCHAR2(100); 
  v_docstatus VARCHAR2(100):='';
  v_issotrx VARCHAR2(100):='';
      TYPE RECORD IS REF CURSOR;
  Cur_OrderLines RECORD;

BEGIN

  IF AD_isTriggerEnabled()='N' THEN IF DELETING THEN RETURN OLD; ELSE RETURN NEW; END IF;
  END IF;

  IF (UPDATING) THEN
  -- Verificar nuevo estado de orden

  v_docstatus = :new.docstatus;
  v_issotrx= :new.issotrx;
  v_reason_clousure = COALESCE( (SELECT em_ssfps_reasons_clousure_id FROM c_order WHERE c_order_id = :new.c_order_id), '');
    IF(v_docstatus = 'CL' and v_issotrx='Y') THEN
      IF(length(v_reason_clousure) = 0)THEN
        RAISE_APPLICATION_ERROR(-20000,'Para cerrar un pedido debe agregar el motivo del cierre en la cabecera del pedido.');
      END IF;
    END IF;

  END IF;


  END SSFPS_ORDER_CLOUSURE_TRG
